syntax = "proto3";

package api.v1;

// Previously: string email = 2; legacy_id = 3; — both removed without a
// reserved declaration, so a future field could silently reuse tag 2 or 3
// and corrupt data on the wire for any client still on the old schema.
message User {
  string id = 1;
}

syntax = "proto3";

package api.v1;

message User {
  reserved 2, 3;
  reserved "email", "legacy_id";
  string id = 1;
}
